                budget_transitions.push(TierTransition {
                    entry_id: *entry_id,
                    scope_id: entry.scope_id.clone(),
                    memory_type: entry.memory_type,
                    old_tier: *current_tier,
                    new_tier: Tier::Warm,
                    retention_score: *score,
